<script>
    import { Link } from "svelte-routing";
    import allContent from "../../data/content.json";

    const scienceContent = allContent.filter(item => item.tags.includes("#science"));
    const subTags = [...new Set(scienceContent.flatMap(item => item.tags).filter(t => t !== "#science"))].sort((a, b) => a.localeCompare(b, "ko"));

    let selectedTag = "";

    $: displayed = selectedTag
        ? scienceContent.filter(item => item.tags.includes(selectedTag))
        : scienceContent;

    function selectTag(tag) {
        selectedTag = selectedTag === tag ? "" : tag;
    }
</script>

<div class="page-shell category-page">
    <header class="cat-header">
        <span class="section-kicker">Science</span>
        <h1>자연 과학</h1>
        <span class="cat-count">{scienceContent.length}개의 글</span>
    </header>

    <nav class="cat-filter" aria-label="자연 과학 카테고리 필터">
        <button class="cat-tag" class:active={selectedTag === ""} on:click={() => selectTag("")}>전체</button>
        {#each subTags as tag}
            <button class="cat-tag" class:active={selectedTag === tag} on:click={() => selectTag(tag)}>{tag}</button>
        {/each}
    </nav>

    <div class="cat-list">
        {#each displayed as item}
            <Link to={`/content/${item.id}`} class="cat-item">
                <div class="cat-item-top">
                    <time>{item.date}</time>
                    <div class="cat-item-tags">
                        {#each item.tags.filter(t => t !== "#science").slice(0, 3) as tag}
                            <span>{tag}</span>
                        {/each}
                    </div>
                </div>
                <h2>{item.title}</h2>
                <p>{item.description}</p>
            </Link>
        {/each}
        {#if displayed.length === 0}
            <p class="empty">해당 태그에 일치하는 글이 없습니다.</p>
        {/if}
    </div>
</div>

