<script>
    import { onMount } from "svelte";
    import { Link, navigate } from "svelte-routing";
    import HeroWebGL from "./HeroWebGL.svelte";
    import allContent from "../../data/content.json";

    const mathContent = allContent.filter(item => item.tags.includes("#math"));
    const scienceContent = allContent.filter(item => item.tags.includes("#science"));
    const csContent = allContent.filter(item => item.tags.includes("#cs"));

    let blogSection;

    function scrollToBlog() {
        blogSection && blogSection.scrollIntoView({ behavior: "smooth" });
    }

    /* Intersection observer for fade-in */
    let fadeEls = [];
    onMount(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add("visible");
                    }
                });
            },
            { threshold: 0.06, rootMargin: "0px 0px -30px 0px" }
        );

        setTimeout(() => {
            fadeEls.forEach((el) => {
                if (el) observer.observe(el);
            });
        }, 100);

        return () => observer.disconnect();
    });

    function goToContent(id) {
        navigate(`/content/${id}`);
    }

    let fadeIdx = 0;
    function nextFade() { return fadeIdx++; }
</script>

<div class="home-redesign">
    <!-- ════════════════════════════════════════════
         SECTION 1: INTERACTIVE HERO
         ════════════════════════════════════════════ -->
    <HeroWebGL onScrollHint={scrollToBlog} />

    <!-- ════════════════════════════════════════════
         SECTION 2: THREE-COLUMN ARCHIVE
         ════════════════════════════════════════════ -->
    <section class="blog-section" bind:this={blogSection} id="blog-section">
        <div class="archive-inner">
            <!-- Archive Header -->
            <header class="archive-header fade-item" bind:this={fadeEls[nextFade()]}>
                <h1 class="archive-title">Archive</h1>
                <p class="archive-subtitle">수학, 자연 과학, 컴퓨터 과학에 대한 지식 기록</p>
            </header>

            <!-- Three Category Columns -->
            <div class="category-grid">
                <!-- ── 수학 ── -->
                <div class="category-column fade-item" bind:this={fadeEls[nextFade()]}>
                    <header class="col-header">
                        <div>
                            <span class="col-kicker">Mathematics</span>
                            <h2 class="col-title">수학</h2>
                        </div>
                        <Link to="/mathpage" class="col-more">전체 보기</Link>
                    </header>
                    <div class="col-list">
                        {#each mathContent as item}
                            <a class="col-item" href={`/content/${item.id}`} on:click|preventDefault={() => goToContent(item.id)}>
                                <h3>{item.title}</h3>
                                <p>{item.description}</p>
                                <time>{item.date}</time>
                            </a>
                        {/each}
                    </div>
                </div>

                <!-- ── 자연 과학 ── -->
                <div class="category-column fade-item" bind:this={fadeEls[nextFade()]}>
                    <header class="col-header">
                        <div>
                            <span class="col-kicker">Science</span>
                            <h2 class="col-title">자연 과학</h2>
                        </div>
                        <Link to="/sciencepage" class="col-more">전체 보기</Link>
                    </header>
                    <div class="col-list">
                        {#each scienceContent as item}
                            <a class="col-item" href={`/content/${item.id}`} on:click|preventDefault={() => goToContent(item.id)}>
                                <h3>{item.title}</h3>
                                <p>{item.description}</p>
                                <time>{item.date}</time>
                            </a>
                        {/each}
                    </div>
                </div>

                <!-- ── 컴퓨터 과학 ── -->
                <div class="category-column fade-item" bind:this={fadeEls[nextFade()]}>
                    <header class="col-header">
                        <div>
                            <span class="col-kicker">Computer Science</span>
                            <h2 class="col-title">컴퓨터 과학</h2>
                        </div>
                        <Link to="/cspage" class="col-more">전체 보기</Link>
                    </header>
                    <div class="col-list">
                        {#each csContent as item}
                            <a class="col-item" href={`/content/${item.id}`} on:click|preventDefault={() => goToContent(item.id)}>
                                <h3>{item.title}</h3>
                                <p>{item.description}</p>
                                <time>{item.date}</time>
                            </a>
                        {/each}
                    </div>
                </div>
            </div>
        </div>
    </section>
</div>

