                    transform 0.7s cubic-bezier(0.22, 1, 0.36, 1);
    }

    :global(.fade-item.visible) {
        opacity: 1;
        transform: translateY(0);
    }

    /* Stagger columns */
    .category-grid .fade-item:nth-child(1) { transition-delay: 0s; }
    .category-grid .fade-item:nth-child(2) { transition-delay: 0.12s; }
    .category-grid .fade-item:nth-child(3) { transition-delay: 0.24s; }

    /* ── Responsive ── */
