<script>
    import { onMount, onDestroy } from 'svelte';
    import { Link } from "svelte-routing";
    import Markdown from 'svelte-markdown';
    import allContent from "../data/content.json";

    export let id;

    let contentItem = null;
    let markdownContent = "";
    let errorMessage = "";
    let scriptElement = null; // To keep track of dynamically added script

    onMount(async () => {
        contentItem = allContent.find(item => item.id === id);

        if (contentItem) {
            if (contentItem.mdFile) {
                try {
                    const response = await fetch(`/Contents/${contentItem.mdFile}`);
                    if (!response.ok) {
                        throw new Error(`HTTP error! status: ${response.status}`);
                    }
                    markdownContent = await response.text();
                } catch (error) {
                    console.error("Error loading markdown file:", error);
                    errorMessage = "콘텐츠를 불러오는 데 실패했습니다.";
                }
            } else if (contentItem.jsFile) {
                try {
                    scriptElement = document.createElement('script');
                    scriptElement.src = `/Contents/${contentItem.jsFile}`;
                    scriptElement.async = true;
                    document.body.appendChild(scriptElement);

                    // Optional: If the JS file exports a function to render, call it here
                    // For now, just loading the script is enough.
                    // You might need a way for the JS file to signal it's ready or to expose a global function.

                } catch (error) {
                    console.error("Error loading JavaScript file:", error);
                    errorMessage = "인터프리터 스크립트를 불러오는 데 실패했습니다.";
                }
            } else {
                errorMessage = "콘텐츠 형식을 알 수 없습니다.";
            }
        } else {
            errorMessage = "콘텐츠를 찾을 수 없습니다.";
        }
    });

    onDestroy(() => {
        if (scriptElement && scriptElement.parentNode) {
            scriptElement.parentNode.removeChild(scriptElement);
        }
    });
</script>

<main class="page-shell">
    {#if contentItem}
        <article class="detail-shell glass-panel">
            <header class="detail-header">
                <div class="detail-meta">
                    <span class="section-kicker">Content Detail</span>
                    <p class="tags">{contentItem.tags.join(' ')}</p>
                </div>
                <div class="header-main">
                    <div>
                        <h1>{contentItem.title}</h1>
                        <p class="description">{contentItem.description}</p>
                    </div>
                    <div class="header-side">
                        <p class="date">{contentItem.date}</p>
                        <Link to="/" class="back-link">홈으로</Link>
                    </div>
                </div>
            </header>

            {#if contentItem.mdFile}
                <div class="markdown-body">
                    <Markdown source={markdownContent} />
                </div>
            {:else if contentItem.jsFile}
                <div class="js-content-container">
                    <div id="python-interpreter-target"></div>
                </div>
            {/if}
        </article>

    {:else if errorMessage}
        <p class="error-message">{errorMessage}</p>
    {:else}
        <p>로딩 중...</p>
    {/if}
</main>

